    if (props.isOpen && appContext.isLoggedIn && !appContext.isLoading) {
      refetch()
    }
  }, [props.isOpen, appContext.isLoggedIn, appContext.isLoading, refetch])

  // フォーカスタイムアウト時の自動リフレッシュ
  useEffect(() => {
    if (isTimeout && props.isOpen && appContext.isLoggedIn) {
      refetch().catch((error) => {
