                canvas.width = img.width
                canvas.height = img.height
                const ctx = canvas.getContext("2d")
                ctx?.drawImage(img, 0, 0)
                const webpDataURL = canvas.toDataURL("image/webp")
                props.items.push({
                  id: props.items.length,
                  content: webpDataURL,
                })
                props.onChangeItems([...props.items])
