    if (props.items.length === 0) {
      if (props.setOgpBase64) {
        props.setOgpBase64(null)
      }
      if (props.setIsThumbnailLandscape) {
        props.setIsThumbnailLandscape(false)
      }
      if (props.setThumbnailBase64) {
        props.setThumbnailBase64(null)
