        )}

        <SortableItems
          items={props.items}
          isDeletable={!props.isOnlyMove}
          setItems={props.setItems}
          setIndexList={props.setIndexList}
          optionalButton={
            <Button
              className="absolute bottom-2 left-2 size-6 md:h-8 md:w-8"
              size={"icon"}
              onClick={() => {}}
            >
              <PencilLineIcon className="size-4 md:h-6 md:w-6" />
