    tags.length > 0 ? tags[Math.floor(Math.random() * tags.length)] : null

  const _navigate = useNavigate()

  const { data: pass } = useQuery(viewerCurrentPassQuery, {})

  const { data: advertisements } = useQuery(randomCustomerAdvertisementQuery, {
    variables: {
      where: {
        isSensitive: false,
        page: "work",
      },
    },
