}

// RequestWorkBotGradingMutation の定義
const RequestWorkBotGradingMutation = graphql(
  `mutation RequestWorkBotGrading($input: RequestWorkBotGradingInput!) {
    requestWorkBotGrading(input: $input) {
      id
      title
      isBotGradingEnabled
