      smallThumbnailImageWidth
      smallThumbnailImageHeight
      thumbnailImagePosition
      subWorksCount
      ogpThumbnailImageUrl
      tagNames
      createdAt
      model
      modelHash
      generationModelId
      workModelId
      isTagEditable
      isCommentsEditable
      isPromotion
      isGeneration
      ogpThumbnailImageUrl
      prompt
      negativePrompt
      noise
      seed
      steps
      sampler
      scale
      strength
      vae
      clipSkip
      otherGenerationParams
      pngInfo
      style
      url
