  const locale = useLocale()
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const updateQueryParams = useUpdateQueryParams()

  // ------ local state ------
  const [currentTab, setCurrentTab] = useState(
    searchParams.get("tab") ?? "home",
