    setIsDialogMode(mode)
    if (typeof window !== "undefined") {
      try {
        localStorage.setItem("aipictors-dialog-mode", JSON.stringify(mode))
      } catch (error) {
        console.error("Failed to save dialog mode to localStorage:", error)
