  const isBlurDefault = isBlurResp?.viewer?.isBlurSensitiveImage

  const [isBlur, setIsBlur] = React.useState(isBlurDefault)

  const onSave = async () => {
    // 設定に基づいてpreferenceRatingを決定
    let preferenceRating: IntrospectionEnum<"PreferenceRating"> = "G"

