      } else {
        preferenceRating = "G"
      }
    }

    await updateUserSetting({
      variables: {
        input: {
          preferenceRating: preferenceRating,
          isBlurSensitiveImage: isBlur,
        },
      },
    })
    toast(t("保存しました", "Settings saved"))
