            if (event.key !== "Enter" && event.key !== " ") return
            event.preventDefault()
            if (isFollowing || isUnFollowing) return
            onFollow()
          }}
          className={cn(
            isFollowing || isUnFollowing ? "w-full opacity-80" : " w-full",
          )}
        >
          {triggerNode}
        </div>
      )}
    </div>
  )
}

const followTagMutation = graphql(
  `mutation FollowTag($input: FollowTagInput!) {
    followTag(input: $input)
  }`,
)

const unfollowTagMutation = graphql(
  `mutation UnFollowTag($input: UnfollowTagInput!) {
    unfollowTag(input: $input)
  }`,
)

import type React from "react"
import { useState, useRef, useEffect } from "react"

type Props = {
  triggerChildren: React.ReactNode
  children: React.ReactNode
  oneTimeExpand?: boolean // 一度切りの展開フラグ
  onExpandChange?: (isOpen: boolean) => void
  className?: string
  hidden?: boolean
}

export function ExpansionTransition (props: Props): React.ReactNode {
  const [isFilterOpen, setIsFilterOpen] = useState(false)
  const [hasExpanded, setHasExpanded] = useState(false) // 追加: 展開済みフラグ
  const [maxHeight, setMaxHeight] = useState("0px")
  const [opacity, setOpacity] = useState(0)
  const contentRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (isFilterOpen && contentRef.current) {
      setMaxHeight(`${contentRef.current.scrollHeight}px`)
      setOpacity(1)
      if (props.oneTimeExpand) {
        setHasExpanded(true)
      }
    } else {
      setMaxHeight("0px")
      setOpacity(0)
    }
  }, [isFilterOpen, props.oneTimeExpand])

  const onToggleFilterButton = () => {
    if (!hasExpanded || !props.oneTimeExpand) {
      setIsFilterOpen(!isFilterOpen)
      if (props.onExpandChange) {
        props.onExpandChange(!isFilterOpen)
      }
    }
  }

  return (
    <>
      {!hasExpanded && (
        // biome-ignore lint/a11y/useKeyWithClickEvents: <explanation>
        <div onClick={onToggleFilterButton}>{props.triggerChildren}</div>
      )}
      {isFilterOpen && (
        <div
          ref={contentRef}
          style={{
            maxHeight: maxHeight,
            opacity: opacity,
            overflow: props.hidden ? "hidden" : "visible",
            transition: "max-height 0.5s ease, opacity 0.5s ease",
          }}
          className={props.className}
        >
          {props.children}
        </div>
      )}
    </>
  )
}

