import { useCallback, useState } from "react"

type Props = {
  onPrev: () => void
  onNext: () => void
  children: React.ReactNode
}

/**
 * スワイプエリア
 * childrenで指定された領域についてスマホ、PCでスワイプ操作可能にする
 */
export function SwipeArea (props: Props): React.ReactNode {
  const [startPosition, setStartPosition] = useState<number | null>(null)

  const handleTouchStart = useCallback(
    (e: React.TouchEvent<HTMLDivElement>) => {
      const touch = e.touches[0]
      setStartPosition(touch.clientX)
    },
    [],
  )

  const handleTouchEnd = useCallback(
    (e: React.TouchEvent<HTMLDivElement>) => {
      if (startPosition == null) return

      const touch = e.changedTouches[0]
      const endPosition = touch.clientX
      const distance = endPosition - startPosition

      if (distance > 50) {
        props.onPrev()
      } else if (distance < -50) {
        props.onNext()
      }

      setStartPosition(null)
    },
    [props.onPrev, props.onNext, startPosition],
  )

  const handleMouseDown = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
    setStartPosition(e.clientX)
  }, [])

  const handleMouseUp = useCallback(
    (e: React.MouseEvent<HTMLDivElement>) => {
      if (startPosition == null) return

      const endPosition = e.clientX
      const distance = endPosition - startPosition

      if (distance > 50) {
        props.onPrev()
      } else if (distance < -50) {
        props.onNext()
      }

      setStartPosition(null)
    },
    [props.onPrev, props.onNext, startPosition],
  )

  return (
    <div
      onTouchStart={handleTouchStart}
      onTouchEnd={handleTouchEnd}
      onMouseDown={handleMouseDown}
      onMouseUp={handleMouseUp}
      style={{ touchAction: "none" }} // Prevents scrolling during swipe on touch devices
    >
      {props.children}
    </div>
  )
}

// https://github.com/JaleelB/emblor/blob/main/website/components/tag/autocomplete.tsx

import type React from "react"
import {
  Command,
  CommandList,
  CommandItem,
  CommandGroup,
  CommandEmpty,
} from "~/components/ui/command"
import type { Tag as TagType } from "./tag-input"

type AutocompleteProps = {
  tags: TagType[]
  setTags: React.Dispatch<React.SetStateAction<TagType[]>>
  autocompleteOptions: TagType[]
  maxTags?: number
  onTagAdd?: (tag: string) => void
  allowDuplicates: boolean
  children: React.ReactNode
}

export function Autocomplete ({
  tags,
  setTags,
  autocompleteOptions,
  maxTags,
  onTagAdd,
  allowDuplicates,
  children,
}: AutocompleteProps): React.ReactNode {
  return (
    <Command className="border">
      {children}
      <CommandList>
        <CommandEmpty>{"検索結果なし"}</CommandEmpty>
        <CommandGroup heading="">
          {autocompleteOptions.map((option) => (
            <CommandItem key={option.id}>
              {/* biome-ignore lint/a11y/useKeyWithClickEvents: <explanation> */}
              <div
                className="w-full"
                onClick={() => {
                  if (maxTags && tags.length >= maxTags) return
                  if (
                    !allowDuplicates &&
                    tags.some((tag) => tag.text === option.text)
                  )
                    return
                  setTags([...tags, option])
                  onTagAdd?.(option.text)
                }}
              >
                {option.text}
              </div>
            </CommandItem>
          ))}
        </CommandGroup>
      </CommandList>
    </Command>
  )
}

import React from "react"
import type { Tag as TagType } from "~/components/tag/tag-input"
import { cn } from "~/lib/utils"
import { Tag, type TagProps } from "~/components/tag/tag"

export type TagListProps = {
  tags: TagType[]
  customTagRenderer?: (tag: TagType) => React.ReactNode
  direction?: TagProps["direction"]
  onSortEnd: (oldIndex: number, newIndex: number) => void
} & Omit<TagProps, "tagObj">

const _DropTarget: React.FC = () => {
  return <div className={cn("h-full rounded-md bg-secondary/50")} />
}

export function TagList ({
  tags,
  customTagRenderer,
  direction,
  draggable,
  onSortEnd,
  ...tagListProps
}: TagListProps): React.ReactNode {
  const [draggedTagId, setDraggedTagId] = React.useState<string | null>(null)

  const handleMouseDown = (id: string) => {
    setDraggedTagId(id)
  }

  const handleMouseUp = () => {
    setDraggedTagId(null)
  }

  if (tags.length === 0) {
    return null
  }

  return (
    <div
      className={cn("rounded-md", {
        "flex flex-wrap gap-2": direction === "row",
        "flex flex-col gap-2": direction === "column",
      })}
    >
      {draggable ? (
        <div className="list flex flex-wrap gap-2">
          {tags.map((tagObj) => (
            <div
              key={tagObj.id}
              onMouseDown={() => handleMouseDown(tagObj.id)}
              onMouseLeave={handleMouseUp}
              className={cn(
                {
                  "rounded-md border border-primary border-solid":
                    draggedTagId === tagObj.id,
                },
                "transition-all duration-200 ease-in-out",
              )}
            >
              {customTagRenderer ? (
                customTagRenderer(tagObj)
              ) : (
                <Tag tagObj={tagObj} {...tagListProps} />
              )}
            </div>
          ))}
        </div>
      ) : (
        tags.map((tagObj) =>
          customTagRenderer ? (
            customTagRenderer(tagObj)
          ) : (
            <Tag key={tagObj.id} tagObj={tagObj} {...tagListProps} />
          ),
        )
      )}
    </div>
  )
}

